export const builtinStyles = {
  tooltip: tooltipStyles,
  dropdown: dropdownStyles,
  menu: dropdownStyles,
}

if (typeof popper.autoHide === 'function') {
  const result = popper.autoHide(event)
  popper.lastAutoHide = result
  return result
}

el.addEventListener('touchstart', onTouchStart, supportsPassive
    ? {
      passive: true,
    }
    : false)

const tableFieldDefinitions = {
  props: ['prop', 'type', 'default', 'description'],
  emits: ['event', 'args', 'description'],
  slots: ['name', 'scope', 'description'],
  exposed: ['name', 'type', 'description'],
} as const satisfies { [P in ComponentItemFree]: TableFieldRaw[] }

const inactiveFinancialBackers = groupedCollectiveMembers.BACKER.filter((el) => {
  const lastTransactionDate = new Date(el.lastTransactionAt)
  return lastTransactionDate < oneYearAgo && lastTransactionDate >= twoYearsAgo
})

const md = new MarkdownIt({
  html: false, // Disable HTML tags in source for security
  breaks: false,
  linkify: true,
})

const appDefaults = {
  BButton: {
    variant: 'primary' as const, // This will merge with existing BButton defaults
  },
}

const state = computed(() =>
  // Return false (invalid) if new tag is a duplicate
  tags.value.indexOf(newTag.value.trim()) > -1 ? false : null
)

const state = computed(() =>
  // Overall component validation state
  dirty.value ? tags.value.length > 2 && tags.value.length < 9 : null
)

const click = (place: Placement = 'start') => {
  placement.value = place
  show.value = !show.value
}

const onFormOverlayShown = () => {
  // Focus on the dialog ok button when the overlay is shown
  successbutton.value?.$el.focus()
}

type BTableProviderContext<T = unknown> = {
  sortBy: BTableSortBy[] | undefined
  filter: string | undefined
  currentPage: number
  perPage: number
}

const boundary = computed<Boundary | undefined>(() =>
  isBoundary(props.boundary) ? props.boundary : undefined
)

const _props = withDefaults(defineProps<BDropdownFormProps>(), {
  formClass: undefined,
  novalidate: undefined,
  validated: undefined,
  wrapperAttrs: undefined,
})

const handleControlClick = () => {
  // Don't trigger if clicking the button itself (button has its own handler with .stop)
  // Don't trigger if disabled
  if (!props.disabled) {
    openFileDialog()
  }
}

const computedBlankImgSrc = computed(() =>
  makeBlankImgSrc(computedDimensions.value.width, computedDimensions.value.height, props.blankColor)
)

interface LabelClasesItemsInput {
  plain?: boolean
  button?: boolean
  buttonVariant?: ButtonVariant | null
  size?: Size
}

interface GroupClassesItemsInput {
  validated?: boolean
  buttons?: boolean
  stacked?: boolean
  size?: Size
}

export interface ElementWithScrollspy extends HTMLElement {
  $__scrollspy?: Record<number, ReturnType<typeof useScrollspy>>
}

if (instance) {
  instance.destroying = true
  delete (elWithProps[propertyName] as Record<string, unknown>)[uid]
}
